void unsafe_strcpy(char* dest, const char* src) {
    strcpy(dest, src);  // No bounds checking!
}

int read_user_input(char* buffer, int max_size) {
    char temp[256];
    printf("Enter input: ");
    gets(temp);  // Dangerous! No bounds check
    if (strlen(temp) > max_size) {
        return -1;
    }
    strcpy(buffer, temp);
    return 0;
}

int parse_integer(const char* str) {
    int value = 0;
    int i = 0;
    while (str[i] != '\0') {
        value = value * 10 + (str[i] - '0');  // Integer overflow possible
        i++;
    }
    return value;
}

char* allocate_buffer(size_t size) {
    char* buf = (char*)malloc(size);
    if (!buf) {
        printf("Allocation failed\n");
        return NULL;
    }
    memset(buf, 0, size + 1);  // Off-by-one error!
    return buf;
}
